// Caché con expiración — 5 minutos
function cachear(clave, obtenerValor, ttlMin = 5) {
  return async function() {
    const texto = localStorage.getItem(`cache:${clave}`);
    if (texto) {
      const { valor, expira } = JSON.parse(texto);
      if (Date.now() < expira) {
        console.log('[caché] usando datos guardados');
        return valor;
      }
    }
    console.log('[caché] cargando datos frescos');
    const valor = await obtenerValor();
    localStorage.setItem(`cache:${clave}`, JSON.stringify({
      valor,
      expira: Date.now() + ttlMin * 60 * 1000
    }));
    return valor;
  };
}

const obtenerUsuarios = cachear('usuarios', () =>
  fetch('https://jsonplaceholder.typicode.com/users').then(r => r.json())
);

await obtenerUsuarios(); // carga de red
await obtenerUsuarios(); // usa caché (5 min)

// Storage con namespace — API limpia
function crearStorage(namespace) {
  const prefix = `${namespace}:`;
  return {
    get(clave) {
      const v = localStorage.getItem(prefix + clave);
      return v ? JSON.parse(v) : null;
    },
    set(clave, valor) {
      localStorage.setItem(prefix + clave, JSON.stringify(valor));
    },
    remove(clave) {
      localStorage.removeItem(prefix + clave);
    },
    limpiar() {
      Object.keys(localStorage)
        .filter(k => k.startsWith(prefix))
        .forEach(k => localStorage.removeItem(k));
    }
  };
}

const authStorage = crearStorage('auth');
const appStorage = crearStorage('app');

authStorage.set('token', 'abc123');
appStorage.set('token', 'diferente'); // no colisiona

console.log(authStorage.get('token')); // 'abc123'
console.log(appStorage.get('token'));  // 'diferente'

// Persistir el estado de la app (patrón Redux-like)
const CLAVE_ESTADO = 'appEstado';

function cargarEstado() {
  try {
    const texto = localStorage.getItem(CLAVE_ESTADO);
    return texto ? JSON.parse(texto) : undefined;
  } catch {
    return undefined;
  }
}

function guardarEstado(estado) {
  try {
    localStorage.setItem(CLAVE_ESTADO, JSON.stringify(estado));
  } catch (error) {
    console.warn('No se pudo persistir el estado:', error.message);
  }
}

// Cargar estado inicial
let estado = cargarEstado() ?? {
  usuario: null,
  tema: 'oscuro',
  progreso: {}
};

// Cada vez que cambia el estado, persistir
estado.tema = 'claro';
guardarEstado(estado);

