function guardarConFecha(clave, valor) {
  const datos = { valor, guardadoEn: Date.now() };
  localStorage.setItem(clave, JSON.stringify(datos));
}

function leerConFecha(clave) {
  const texto = localStorage.getItem(clave);
  if (!texto) return null;
  return JSON.parse(texto);
}

guardarConFecha('config', { tema: 'oscuro' });
const leido = leerConFecha('config');
const noExiste = leerConFecha('no-existe');

function estaExpirado(datos, ttlMinutos) {
  const ttlMs = ttlMinutos * 60 * 1000;
  return Date.now() - datos.guardadoEn > ttlMs;
}

// Datos guardados hace 2 minutos (120000 ms)
const hace2min = { valor: 'test', guardadoEn: Date.now() - 120_000 };
// Datos guardados hace 10 minutos
const hace10min = { valor: 'test', guardadoEn: Date.now() - 600_000 };

const expirado1 = estaExpirado(hace2min, 5);  // 2 min < 5 min → false
const expirado2 = estaExpirado(hace10min, 5); // 10 min > 5 min → true

function crearStorage(namespace) {
  const prefix = namespace + ':';

  return {
    set(clave, valor) {
      localStorage.setItem(prefix + clave, JSON.stringify(valor));
    },
    get(clave) {
      const texto = localStorage.getItem(prefix + clave);
      return texto !== null ? JSON.parse(texto) : null;
    },
    remove(clave) {
      localStorage.removeItem(prefix + clave);
    }
  };
}

